const input = $input.first()?.json || {};
const payload = input.body && typeof input.body === 'object' ? input.body : input;

const normalize = (value, fallback = '') => {
  if (value === null || value === undefined) return fallback;
  const text = String(value).trim();
  return text || fallback;
};

const readEnv = (key, fallback = '') => {
  const envObject = typeof $env === 'object' && $env ? $env : null;
  if (envObject && envObject[key] !== undefined && envObject[key] !== null) {
    return normalize(envObject[key], fallback);
  }

  if (
    typeof process !== 'undefined' &&
    process &&
    process.env &&
    process.env[key] !== undefined &&
    process.env[key] !== null
  ) {
    return normalize(process.env[key], fallback);
  }

  return fallback;
};

const safeInt = (value, fallback = 0) => {
  const parsed = Number.parseInt(String(value ?? ''), 10);
  return Number.isFinite(parsed) ? parsed : fallback;
};

const clip = (value, max = 12000) => {
  const text = normalize(value);
  return text.length > max ? text.slice(0, max) : text;
};

const splitUserPoints = (text, maxItems = 10) => {
  const raw = clip(text, 12000);
  if (!raw) return [];

  const lines = raw
    .split(/\r?\n/)
    .map((line) => line.replace(/^[-*\d.)\s]+/, '').trim())
    .filter(Boolean);

  const unique = [];
  for (const line of lines) {
    if (!unique.includes(line)) unique.push(line);
    if (unique.length >= maxItems) break;
  }
  return unique;
};

const numeroProcesso = normalize(payload.numero_processo);
const autor = normalize(payload.autor);
const reu = normalize(payload.reu, 'Nao informado');
const tipoAcao = normalize(payload.tipo_acao);
const fatos = clip(payload.fatos, 12000);
const pedidoAutor = clip(payload.pedido_autor, 8000);
const textoEditadoAoVivo = clip(payload.texto_editado_ao_vivo, 12000);

const arquivoNome = normalize(payload.arquivo_base_nome || payload.arquivo_base);
const arquivoMime = normalize(payload.arquivo_base_mime_type, 'application/octet-stream');
const arquivoTamanhoBytes = safeInt(payload.arquivo_base_tamanho_bytes, 0);
const arquivoConteudoBase64 = normalize(payload.arquivo_base_conteudo_base64);

const modeloMaeTexto = clip(
  payload.modelo_mae_texto || readEnv('MODELO_MAE_CONTESTACAO'),
  15000,
);

const inferTextFromFile = () => {
  if (!arquivoConteudoBase64) return '';

  const lowerName = arquivoNome.toLowerCase();
  const isTextLike =
    arquivoMime.startsWith('text/') ||
    /\.(txt|md|json|csv|xml|html|htm|rtf)$/i.test(lowerName);

  if (!isTextLike) return '';

  try {
    return Buffer.from(arquivoConteudoBase64, 'base64')
      .toString('utf8')
      .replace(/\0/g, '')
      .slice(0, 15000);
  } catch {
    return '';
  }
};

const textoPeticaoBase = inferTextFromFile();
const pontosUsuario = splitUserPoints(textoEditadoAoVivo, 10);

const errors = [];
if (!numeroProcesso) errors.push('numero_processo obrigatorio');
if (!autor) errors.push('autor obrigatorio');
if (!tipoAcao) errors.push('tipo_acao obrigatorio');
if (!fatos) errors.push('fatos obrigatorio');
if (!pedidoAutor) errors.push('pedido_autor obrigatorio');

const cnjRegex = /^\d{7}-\d{2}\.\d{4}\.\d\.\d{2}\.\d{4}$/;
if (numeroProcesso && !cnjRegex.test(numeroProcesso)) {
  errors.push('numero_processo fora do padrao CNJ 0001234-56.2026.8.00.0000');
}

if (arquivoNome && !arquivoConteudoBase64) {
  errors.push('arquivo_base_conteudo_base64 obrigatorio quando arquivo_base_nome for enviado');
}

if (arquivoConteudoBase64 && !arquivoNome) {
  errors.push('arquivo_base_nome obrigatorio quando arquivo_base_conteudo_base64 for enviado');
}

if (arquivoTamanhoBytes > 10 * 1024 * 1024) {
  errors.push('arquivo_base excede o tamanho maximo de 10MB');
}

if (arquivoNome && !/\.(pdf|doc|docx|txt|md|rtf)$/i.test(arquivoNome)) {
  errors.push('arquivo_base deve ser PDF, DOC, DOCX, TXT, MD ou RTF');
}

const regrasAplicadas = [
  'Trigger webhook POST /contestacao ativo',
  'Validacao de campos obrigatorios e formato CNJ',
  'Normalizacao de payload para o agente de IA',
  'Leitura de contexto do usuario (texto_editado_ao_vivo)',
  'Suporte a modelo-mae (payload ou env MODELO_MAE_CONTESTACAO)',
  'Leitura best-effort de peticao base textual (quando arquivo for texto)',
];

if (errors.length) {
  return [
    {
      json: {
        status: 'erro_validacao',
        mensagem: 'Falha de validacao no trigger Webhook Contestacao.',
        erros: errors,
        regras_aplicadas: regrasAplicadas,
        gatilhos_acionados: [{ tipo: 'webhook', metodo: 'POST', path: 'contestacao' }],
        recebido_em: new Date().toISOString(),
      },
    },
  ];
}

return [
  {
    json: {
      status: 'entrada_validada',
      mensagem: 'Entrada validada para processamento do agente de IA.',
      regras_aplicadas: regrasAplicadas,
      gatilhos_acionados: [{ tipo: 'webhook', metodo: 'POST', path: 'contestacao' }],
      contexto: {
        numero_processo: numeroProcesso,
        autor,
        reu,
        tipo_acao: tipoAcao,
        fatos,
        pedido_autor: pedidoAutor,
        texto_editado_ao_vivo: textoEditadoAoVivo,
        pontos_usuario: pontosUsuario,
        modelo_mae_texto: modeloMaeTexto,
        arquivo_base: {
          nome: arquivoNome,
          mime_type: arquivoMime,
          tamanho_bytes: arquivoTamanhoBytes,
          conteudo_texto: textoPeticaoBase,
        },
      },
      recebido_em: new Date().toISOString(),
    },
  },
];

const envelope = $input.first()?.json || {};

if (envelope.status === 'erro_validacao') {
  return [{ json: envelope }];
}

const contexto = envelope.contexto && typeof envelope.contexto === 'object' ? envelope.contexto : {};

const normalize = (value, fallback = '') => {
  if (value === null || value === undefined) return fallback;
  const text = String(value).trim();
  return text || fallback;
};

const readEnv = (key, fallback = '') => {
  const envObject = typeof $env === 'object' && $env ? $env : null;
  if (envObject && envObject[key] !== undefined && envObject[key] !== null) {
    return normalize(envObject[key], fallback);
  }

  if (
    typeof process !== 'undefined' &&
    process &&
    process.env &&
    process.env[key] !== undefined &&
    process.env[key] !== null
  ) {
    return normalize(process.env[key], fallback);
  }

  return fallback;
};

const clip = (value, max = 16000) => {
  const text = normalize(value);
  return text.length > max ? text.slice(0, max) : text;
};

const numeroProcesso = normalize(contexto.numero_processo);
const autor = normalize(contexto.autor);
const reu = normalize(contexto.reu, 'Nao informado');
const tipoAcao = normalize(contexto.tipo_acao);
const fatos = clip(contexto.fatos, 12000);
const pedidoAutor = clip(contexto.pedido_autor, 8000);
const textoEditado = clip(contexto.texto_editado_ao_vivo, 12000);
const pontosUsuario = Array.isArray(contexto.pontos_usuario)
  ? contexto.pontos_usuario.map((item) => normalize(item)).filter(Boolean).slice(0, 10)
  : [];
const modeloMaeTexto = clip(contexto.modelo_mae_texto, 15000);
const textoPeticaoBase = clip(contexto?.arquivo_base?.conteudo_texto, 15000);
const arquivoNome = normalize(contexto?.arquivo_base?.nome);

const regrasAplicadas = Array.isArray(envelope.regras_aplicadas)
  ? [...envelope.regras_aplicadas]
  : [];
regrasAplicadas.push('Aplicacao de regras juridicas de contestacao civil');
regrasAplicadas.push('Priorizacao dos pontos pedidos pelo usuario');
regrasAplicadas.push('Uso de modelo-mae quando disponivel');
regrasAplicadas.push('Persistencia de dados delegada ao backend PostgreSQL/Supabase');

const gatilhosAcionados = Array.isArray(envelope.gatilhos_acionados)
  ? envelope.gatilhos_acionados
  : [{ tipo: 'webhook', metodo: 'POST', path: 'contestacao' }];

const OPENAI_API_KEY = normalize(
  readEnv('OPENAI_API_KEY') || readEnv('OPENAI_KEY') || readEnv('OPENAI_SECRET_KEY'),
);
const OPENAI_MODEL = normalize(
  readEnv('OPENAI_MODEL') || readEnv('OPENAI_RESPONSES_MODEL') || readEnv('OPENAI_CHAT_MODEL'),
  'gpt-5.3-codex',
);
const OPENAI_BASE_URL = normalize(
  readEnv('OPENAI_BASE_URL') || readEnv('OPENAI_API_BASE_URL'),
  'https://api.openai.com/v1',
).replace(/\/+$/, '');
const OPENAI_MAX_OUTPUT_TOKENS = Math.max(
  700,
  Number.parseInt(readEnv('OPENAI_MAX_OUTPUT_TOKENS', '2600'), 10) || 2600,
);
const OPENAI_TIMEOUT_MS = Math.max(
  10000,
  Number.parseInt(readEnv('OPENAI_TIMEOUT_MS', '35000'), 10) || 35000,
);
const OPENAI_TEMPERATURE_RAW = Number.parseFloat(readEnv('OPENAI_TEMPERATURE', '0.12'));
const OPENAI_TEMPERATURE = Number.isFinite(OPENAI_TEMPERATURE_RAW)
  ? Math.min(Math.max(OPENAI_TEMPERATURE_RAW, 0), 1)
  : 0.12;
const DB_PROVIDER = normalize(readEnv('CONTESTACAO_DB_PROVIDER'), 'backend_postgresql_supabase');
const DB_TABLE = normalize(readEnv('CONTESTACAO_DB_TABLE'), 'contestacoes');
const DB_STATUS_FIELD = normalize(readEnv('CONTESTACAO_DB_STATUS_FIELD'), 'status');

const buildFallbackDraft = (reason = 'fallback_local') => {
  const pontosUsuarioTexto = pontosUsuario.length
    ? `Pontos solicitados pelo usuario: ${pontosUsuario.join('; ')}.`
    : 'Sem pontos adicionais informados pelo usuario.';

  const sintese = `Trata-se de contestacao referente ao processo ${numeroProcesso}, proposta por ${autor} em face de ${reu}, no contexto de ${tipoAcao}.`;
  const fundamentos = `Com base nos fatos informados (${fatos}), impugna-se a narrativa autoral e requer-se a improcedencia dos pedidos, preservando contraditorio e ampla defesa. ${pontosUsuarioTexto}`;
  const pedidos = `Requer-se: (i) recebimento da contestacao; (ii) improcedencia dos pedidos autorais (${pedidoAutor}); (iii) producao de provas em direito admitidas.`;
  const observacoesModelo = modeloMaeTexto
    ? 'Modelo-mae identificado e sinalizado para revisao humana.'
    : 'Sem modelo-mae explicito. Estrutura padrao aplicada.';

  const minutaBase = [
    'I - Sintese da Demanda',
    sintese,
    '',
    'II - Fundamentos de Defesa',
    fundamentos,
    '',
    'III - Pedidos',
    pedidos,
    '',
    textoEditado ? 'IV - Pontos do Usuario\n' + textoEditado : '',
    textoPeticaoBase ? 'V - Trechos da Peticao Base (analise textual)\n' + textoPeticaoBase.slice(0, 1500) : '',
    'VI - Observacoes',
    observacoesModelo,
  ]
    .filter(Boolean)
    .join('\n\n');

  return {
    json: {
      status: 'ok',
      mensagem: 'Contestacao processada em modo fallback local do agente.',
      numero_processo: numeroProcesso,
      protocolo_n8n: `N8N-${Date.now()}`,
      gatilhos_acionados: gatilhosAcionados,
      regras_aplicadas: [...regrasAplicadas, 'Fallback local sem chamada externa'],
      engine_ia: {
        provider: 'fallback_local',
        model: 'deterministico',
        motivo: reason,
      },
      infra: {
        modelo_configurado: OPENAI_MODEL,
        banco_provider: DB_PROVIDER,
        banco_tabela: DB_TABLE,
        banco_campo_status: DB_STATUS_FIELD,
        persistencia: 'realizada_no_backend',
      },
      minuta: {
        texto_base: minutaBase,
        secoes: {
          sintese,
          fundamentos,
          pedidos,
        },
        resumo_estrategico: 'Minuta base gerada localmente para revisao humana.',
        tese_central: 'Impugnacao dos pedidos autorais e pedido de improcedencia.',
        pontos_atendidos: pontosUsuario,
        riscos: ['Sem IA externa ativa: revisar fundamentacao legal manualmente.'],
      },
      auditoria: {
        modelo_mae_utilizado: Boolean(modeloMaeTexto),
        peticao_base_lida: Boolean(textoPeticaoBase),
        pontos_usuario_identificados: pontosUsuario.length,
        arquivo_base_nome: arquivoNome || '',
      },
      contexto: {
        autor,
        reu,
        tipo_acao: tipoAcao,
      },
      recebido_em: new Date().toISOString(),
    },
  };
};

if (!OPENAI_API_KEY) {
  return [buildFallbackDraft('OPENAI_API_KEY_nao_configurada')];
}

const stripMarkdownFences = (value) => {
  const trimmed = normalize(value);
  if (!trimmed.startsWith('```')) return trimmed;
  return trimmed
    .replace(/^```(?:json)?\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();
};

const parseModelJson = (value) => JSON.parse(stripMarkdownFences(value));

const systemPrompt = [
  'Voce e um agente juridico especialista em contestacoes civeis no Brasil.',
  'Sua tarefa e redigir minuta de contestacao para revisao humana.',
  'Aplique as regras: objetividade, clareza, sem inventar fatos, sem inventar jurisprudencia ou citacoes numericas especificas.',
  'Se MODELO_MAE existir, preserve estilo e estrutura de secoes do modelo.',
  'Se TEXTO_PETICAO_BASE existir, identifique os pontos centrais da peticao e responda tecnicamente.',
  'Priorize os pontos solicitados pelo usuario em texto_editado_ao_vivo.',
  'Responda SOMENTE JSON valido com as chaves:',
  '{"resumo_estrategico":"...","tese_central":"...","pontos_atendidos":["..."],"sintese":"...","fundamentos":"...","pedidos":"...","observacoes":"...","riscos":["..."]}',
  'Nao use markdown.',
].join(' ');

const userPayload = {
  numero_processo: numeroProcesso,
  autor,
  reu,
  tipo_acao: tipoAcao,
  fatos,
  pedido_autor: pedidoAutor,
  pontos_usuario: pontosUsuario,
  texto_editado_ao_vivo: textoEditado,
  texto_peticao_base: textoPeticaoBase,
  modelo_mae_texto: modeloMaeTexto,
};

const requestBody = {
  model: OPENAI_MODEL,
  temperature: OPENAI_TEMPERATURE,
  max_output_tokens: OPENAI_MAX_OUTPUT_TOKENS,
  input: [
    {
      role: 'system',
      content: [{ type: 'input_text', text: systemPrompt }],
    },
    {
      role: 'user',
      content: [{ type: 'input_text', text: `CASO_JSON:\n${JSON.stringify(userPayload, null, 2)}` }],
    },
  ],
};

const controller = new AbortController();
const timeoutHandle = setTimeout(() => controller.abort(), OPENAI_TIMEOUT_MS);

let openaiPayload = {};

try {
  const response = await fetch(`${OPENAI_BASE_URL}/responses`, {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${OPENAI_API_KEY}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(requestBody),
    signal: controller.signal,
  });

  openaiPayload = await response.json().catch(() => ({}));

  if (!response.ok) {
    const detail = normalize(openaiPayload?.error?.message) || `HTTP_${response.status}`;
    throw new Error(`OpenAI API falhou: ${detail}`);
  }
} catch (error) {
  clearTimeout(timeoutHandle);
  const reason = normalize(error?.message, 'erro_openai').slice(0, 160);
  return [buildFallbackDraft(reason)];
}

clearTimeout(timeoutHandle);

const outputParts = [];
if (typeof openaiPayload?.output_text === 'string' && openaiPayload.output_text.trim()) {
  outputParts.push(openaiPayload.output_text);
}

if (Array.isArray(openaiPayload?.output)) {
  for (const block of openaiPayload.output) {
    if (!Array.isArray(block?.content)) continue;
    for (const contentItem of block.content) {
      const candidateText =
        normalize(contentItem?.text) ||
        normalize(contentItem?.output_text) ||
        normalize(contentItem?.input_text);
      if (candidateText) outputParts.push(candidateText);
    }
  }
}

const rawModelText = outputParts.join('\n').trim();
if (!rawModelText) {
  return [buildFallbackDraft('resposta_openai_sem_conteudo')];
}

let modelData = {};
try {
  modelData = parseModelJson(rawModelText);
} catch {
  return [buildFallbackDraft('resposta_openai_nao_json')];
}

const sinteseIa =
  clip(modelData.sintese, 10000) ||
  `Trata-se de contestacao referente ao processo ${numeroProcesso}, proposta por ${autor} em face de ${reu}, no contexto de ${tipoAcao}.`;

const fundamentosIa =
  clip(modelData.fundamentos, 15000) ||
  `Com base nos fatos informados (${fatos}), impugna-se a narrativa autoral e requer-se a improcedencia dos pedidos.`;

const pedidosIa =
  clip(modelData.pedidos, 8000) ||
  `Requer-se o recebimento da contestacao e a improcedencia do pedido autoral (${pedidoAutor}).`;

const observacoesIa = clip(modelData.observacoes, 6000);
const resumoEstrategico = clip(modelData.resumo_estrategico, 3000) || 'Defesa gerada por IA para revisao humana.';
const teseCentral = clip(modelData.tese_central, 2000) || 'Improcedencia dos pedidos autorais.';

const pontosAtendidos = Array.isArray(modelData.pontos_atendidos)
  ? modelData.pontos_atendidos.map((item) => normalize(item)).filter(Boolean).slice(0, 12)
  : pontosUsuario;

const riscos = Array.isArray(modelData.riscos)
  ? modelData.riscos.map((item) => normalize(item)).filter(Boolean).slice(0, 6)
  : ['Revisar fundamentos e provas antes do protocolo.'];

const minutaBase = [
  'I - Sintese da Demanda',
  sinteseIa,
  '',
  'II - Fundamentos de Defesa',
  fundamentosIa,
  '',
  'III - Pedidos',
  pedidosIa,
  '',
  pontosUsuario.length ? 'IV - Pontos Solicitados pelo Usuario\n- ' + pontosUsuario.join('\n- ') : '',
  observacoesIa ? 'V - Observacoes do Agente de IA\n' + observacoesIa : '',
  riscos.length ? 'VI - Riscos e Pontos de Atencao\n- ' + riscos.join('\n- ') : '',
]
  .filter(Boolean)
  .join('\n\n');

return [
  {
    json: {
      status: 'ok',
      mensagem: 'Contestacao processada pelo agente de IA com regras completas.',
      numero_processo: numeroProcesso,
      protocolo_n8n: `N8N-${Date.now()}`,
      gatilhos_acionados: gatilhosAcionados,
      regras_aplicadas: [...regrasAplicadas, 'Resposta estruturada em JSON para integracao com backend/frontend'],
      engine_ia: {
        provider: 'openai',
        model: OPENAI_MODEL,
        endpoint: `${OPENAI_BASE_URL}/responses`,
        temperature: OPENAI_TEMPERATURE,
        max_output_tokens: OPENAI_MAX_OUTPUT_TOKENS,
      },
      infra: {
        modelo_configurado: OPENAI_MODEL,
        banco_provider: DB_PROVIDER,
        banco_tabela: DB_TABLE,
        banco_campo_status: DB_STATUS_FIELD,
        persistencia: 'realizada_no_backend',
      },
      minuta: {
        texto_base: minutaBase,
        secoes: {
          sintese: sinteseIa,
          fundamentos: fundamentosIa,
          pedidos: pedidosIa,
        },
        resumo_estrategico: resumoEstrategico,
        tese_central: teseCentral,
        pontos_atendidos: pontosAtendidos,
        riscos,
      },
      auditoria: {
        modelo_mae_utilizado: Boolean(modeloMaeTexto),
        peticao_base_lida: Boolean(textoPeticaoBase),
        pontos_usuario_identificados: pontosUsuario.length,
        arquivo_base_nome: arquivoNome || '',
      },
      contexto: {
        autor,
        reu,
        tipo_acao: tipoAcao,
      },
      recebido_em: new Date().toISOString(),
    },
  },
];
